const code = $json.code || '';
return [{
  json: {
    model: 'local-model',
    messages: [
      {
        role: 'user',
        content: `You are a Principal Software Architect reviewing code quality and maintainability.
Your task is to evaluate documentation coverage, test completeness, and architectural decisions.

Code to Review:
${code}

Review Checklist:
- All public functions/classes have JSDoc/Docstring comments
- Unit tests cover critical paths (minimum 80% line coverage)
- Error handling comprehensive with custom error types
- Database queries optimized (no N+1 problems, indexes on foreign keys)
- Configuration externalized via environment variables
- Logging structured and appropriate log levels used
- API endpoints follow REST conventions (proper HTTP methods, status codes)
- React components use hooks correctly with no memory leaks

Output Format:
Return valid JSON with these fields:
{
  "quality_score": number (1-10),
  "strengths": [array of positive observations],
  "areas_for_improvement": [array of improvement items],
  "recommendations": [array of general recommendations]
}

For each area for improvement include:
{
  "area": name of the issue,
  "current_state": description of current problem,
  "target": what should be achieved,
  "fix": specific remediation steps
}

Output ONLY the JSON, no markdown formatting.`
      }
    ],
    temperature: 0.5,
    max_tokens: 2048
  }
}];

const content = $json.choices[0].message.content;
let review;
try {
  review = JSON.parse(content);
} catch (e) {
  review = { raw_output: content };
}
return [{ json: { quality_review: review } }];
